var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"다이브 성공! 목적지에 도착했어요, 승객 여러분!","JPN":"ダイブ成功！　乗客の皆さん、目的地に到着しました！","ENG":"Dive success! We've reached the destination, ladies and gentlemen.","TWN":"躍入成功！各位乘客，我們抵達目的地囉！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"현지 날씨는 흐림, CSE 레벨은 4 입니다! 주의가 필요해요~","JPN":"現在の天気は曇り、CSEレベルは4です！　注意が必要で～す。","ENG":"The current weather is cloudy, with the CSE level of 4. Please proceed with due caution.","TWN":"當地天氣多雲，CSE等級為4！請大家注意～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……잠깐만, 레벨이 4 라고?","JPN":"……ちょっと待って、レベル4？","ENG":"…Hang on, level 4?","TWN":"……等等，你說等級是4？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 4종 침식체도 나타날 수 있다는 뜻이잖아?","JPN":"ってことは、第4種侵食体も現れるってことだよね？","ENG":"That means we could see C.O.s up to Category 4's here, correct?","TWN":"那不就是會出現4類侵蝕體的意思嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그냥 얌전히 부사장님이 시킨 일이나 할 걸 그랬나.","JPN":"大人しく副社長に頼まれた雑務でもしておけばよかった。","ENG":"Maybe I should have just stuck with the Vice President's job.","TWN":"不是說要乖乖地執行副總交代的事嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"CSE 레벨 4라니, 얼마나 고심도까지 다이브한 거죠?","JPN":"CSEレベル4だなんて、どれほど高深度までダイブしたのですか？","ENG":"CSE Level 4? How deep did we dive?","TWN":"CSE等級竟然是4，這是躍入到多高深度？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이대로라면 진입하기에는 너무 위험해요.","JPN":"このまま進むのは非常に危険です。","ENG":"It will be too dangerous to proceed like this.","TWN":"這樣下去進入會有危險，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……아무래도 제가 경솔했다는 생각이 드네요.","JPN":"……どうやら私が軽率だったようですね。","ENG":"…I'm beginning to think that I've been rather rash.","TWN":"……都怪我太草率，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"돌아가서 관리국의 정식 지원을 요청하는 게 좋겠어요.","JPN":"戻って管理局に正式支援を要請したほうがいいでしょう。","ENG":"We should go back and officially ask for Administration support.","TWN":"還是回去向管理局請求正式支援吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……하지만 시간을 끌었다간 선배가 위험해질지도 몰라.","JPN":"……でも、時間をかけると先輩が危ないかもしれない。","ENG":"…But if we delay any further, Shiyoon could be in danger.","TWN":"……但時間拖越久前輩就越危險，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일개 용병 구출하는 일에 관리국이 나서 줄지도 알 수 없고.","JPN":"たかが傭兵一人を救出するために管理局が動いてくれるかもわからないし。","ENG":"Plus, I'm not sure the Administration will get involved with rescuing some random mercenary.","TWN":"而且也不確定管理局是否會因為區區一個傭兵而出手。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장 말대로 위험한 건 사실이야. 나머진 우리한테 맡기고 지금이라도 돌아가.","JPN":"会長の言うとおり危険なのは事実だよ。あとは私たちに任せて、今からでも戻ったほうがいいよ。","ENG":"But you're right. This is dangerous. You can go back now and leave the rest to us.","TWN":"確實像會長說的會有危險，所以其他就交給我們，你們先回去吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기까지 같이 와 준 것만으로도 고마우니까.","JPN":"ここまで一緒に来てくれただけでもありがたいから。","ENG":"I'm grateful that you came this far.","TWN":"你們願意陪我們走到這裡我已經覺得很感謝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는 나와 서윤이 어떻게든 찾아볼게.","JPN":"先輩は私とシズカで何とかして探してみる。","ENG":"Seo Yoon and I will find Shiyoon somehow.","TWN":"我和徐芸無論如何會救出前輩的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"은근슬쩍 나까지 끼워 넣는 걸 보니 능청이 늘었는걸?","JPN":"さりげなく私を巻き込むのはさすがね。ずいぶん図々しくなったものだわ。","ENG":"Think you're pretty smooth, including me like that, huh?","TWN":"竟然默默地把我算進去，看來你挖坑的技巧進步不少呢？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"나도 4종 같은 괴물들이랑 싸우는 건 사양인데.","JPN":"私も第4種みたいな化け物と戦うのはごめんなんだけど。","ENG":"Personally, I'd rather not fight Category 4's either.","TWN":"我也沒有要和4類侵蝕體的意思。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};